import{_ as a,o as e,c as r,a2 as d}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Portfolio","description":"운영 가능한 시스템 설계와 시행착오를 정리한 전문가 기술 기록","frontmatter":{"title":"Portfolio","description":"운영 가능한 시스템 설계와 시행착오를 정리한 전문가 기술 기록","outline":"deep"},"headers":[],"relativePath":"portfolio/index.md","filePath":"portfolio/index.md","lastUpdated":1781652437000}'),o={name:"portfolio/index.md"};function i(n,t,s,l,c,h){return e(),r("div",null,[...t[0]||(t[0]=[d('<h1 id="portfolio" tabindex="-1">Portfolio <a class="header-anchor" href="#portfolio" aria-label="Permalink to &quot;Portfolio&quot;">​</a></h1><p>이 문서들은 프로젝트 소개가 아니라 <strong>운영 가능한 시스템을 만들기 위한 판단 기록</strong>이다. 각 글은 사용 기술보다 문제 정의, 책임 경계, 선택 근거, 운영 검증, 후속 기준을 중심으로 작성했다.</p><p>기술 기반에는 Java/Spring 백엔드가 있다. 다만 실제 프로젝트 범위는 API 서버에 한정되지 않았다. Node.js/NestJS 기반 실행 계층, Vue.js 관리 화면, React 기반 UI, Kafka worker, OpenResty L7, PlanVM DSL runtime, DBHub, Task Manager, Messaging System, WebRTC, Agent 실행 계층까지 제품 운영에 필요한 경계를 함께 다뤘다.</p><h2 id="읽는-기준" tabindex="-1">읽는 기준 <a class="header-anchor" href="#읽는-기준" aria-label="Permalink to &quot;읽는 기준&quot;">​</a></h2><table tabindex="0"><thead><tr><th>관점</th><th>문서에서 확인할 내용</th></tr></thead><tbody><tr><td>운영 통제</td><td>장애, 배포, 설정, DB 접근, batch 실패를 어떻게 추적하고 되돌리는가</td></tr><tr><td>실행 경계</td><td>gateway, worker, runtime, DB, cache, media server, Agent가 어디까지 책임지는가</td></tr><tr><td>변경 관리</td><td>코드 배포 없이 바뀌는 업무 정책을 어떻게 검증하고 승인하는가</td></tr><tr><td>데이터 책임</td><td>SOT, audit, revision, hash, masking, trace를 어떻게 설계하는가</td></tr><tr><td>실시간성</td><td>messaging, WebRTC, gateway에서 session lifecycle과 tail latency를 어떻게 다루는가</td></tr></tbody></table><h2 id="운영-플랫폼" tabindex="-1">운영 플랫폼 <a class="header-anchor" href="#운영-플랫폼" aria-label="Permalink to &quot;운영 플랫폼&quot;">​</a></h2><div class="portfolio-grid"><div class="portfolio-card"><h3>PlanVM DSL Runtime</h3><p>자주 바뀌는 업무 정책을 검증, 배포, 감사, rollback 가능한 실행 단위로 분리한 runtime.</p><a href="./05-planvm-dsl-runtime-platform">읽기 →</a></div><div class="portfolio-card"><h3>DBHub</h3><p>운영 DB 접근을 SQL 실행이 아니라 승인과 감사가 가능한 업무 행위로 다룬 구조.</p><a href="./06-planvm-dbhub">읽기 →</a></div><div class="portfolio-card"><h3>Task Manager</h3><p>흩어진 scheduler를 task definition, run, retry, DLQ, audit이 있는 실행 시스템으로 전환.</p><a href="./10-large-scale-batch-automation-pipeline">읽기 →</a></div><div class="portfolio-card"><h3>Zero Downtime Deployment</h3><p>GitLab/Jenkins 배포를 MinIO versioned bundle, 승인, 감사, rollback 중심으로 확장.</p><a href="./11-zero-downtime-bluegreen-canary-deployment">읽기 →</a></div></div><h2 id="트래픽과-장애-대응" tabindex="-1">트래픽과 장애 대응 <a class="header-anchor" href="#트래픽과-장애-대응" aria-label="Permalink to &quot;트래픽과 장애 대응&quot;">​</a></h2><div class="portfolio-grid"><div class="portfolio-card"><h3>Kafka Incident Monitoring</h3><p>ERP·Groupware·ESS의 운영 이벤트와 장애 이벤트를 수집하고 원인 후보와 해결 힌트를 제공.</p><a href="./01-kafka-erp-groupware-ess-incident-monitoring">읽기 →</a></div><div class="portfolio-card"><h3>Cloud Config and Discovery</h3><p>Consul에서 시작해 Nacos 기반 DUCOS로 확장한 config/discovery 운영 모델.</p><a href="./02-ducos-nacos-config-discovery">읽기 →</a></div><div class="portfolio-card"><h3>OpenResty L7 Layer</h3><p>범용 Gateway와 별개로 조직의 tenant, stage, routing, canary 정책을 담은 L7 경계 계층.</p><a href="./03-openresty-l7-layer">읽기 →</a></div><div class="portfolio-card"><h3>Messaging System</h3><p>고객사 업무 플랫폼으로 확장된 메신저를 Kafka, cache, shard, sync API 중심으로 재설계.</p><a href="./08-large-scale-messaging-system">읽기 →</a></div><div class="portfolio-card"><h3>WebRTC, LiveKit and Janus</h3><p>원격제어에는 LiveKit, 원격 화상회의에는 Janus를 적용하며 media gateway 책임 경계를 검증.</p><a href="./12-webrtc-and-janus">읽기 →</a></div></div><h2 id="업무-도메인과-agent" tabindex="-1">업무 도메인과 Agent <a class="header-anchor" href="#업무-도메인과-agent" aria-label="Permalink to &quot;업무 도메인과 Agent&quot;">​</a></h2><div class="portfolio-grid"><div class="portfolio-card"><h3>CALS Attendance Ledger</h3><p>근태 connector를 조직의 출퇴근, 보정, 연차, HR 계산을 지탱하는 SOT 원장으로 확장.</p><a href="./04-cals-attendance-connector-hub">읽기 →</a></div><div class="portfolio-card"><h3>AI Agent</h3><p>자율형 Agent의 한계를 검토하고, 의도·맥락·slot 판단과 통제 실행을 분리한 업무용 Agent.</p><a href="./07-rasa-agent-sdk-natural-language-agent">읽기 →</a></div><div class="portfolio-card"><h3>Year-end Tax Calculator</h3><p>복잡한 세법·공제 규칙을 deterministic하고 설명 가능한 계산 trace로 구현.</p><a href="./09-year-end-tax-calculator">읽기 →</a></div></div><h2 id="문서별-보강-기준" tabindex="-1">문서별 보강 기준 <a class="header-anchor" href="#문서별-보강-기준" aria-label="Permalink to &quot;문서별 보강 기준&quot;">​</a></h2><p>각 문서는 동일한 구조를 따르되, 단순한 템플릿이 되지 않도록 프로젝트별로 확인해야 할 운영 흔적을 다르게 두었다.</p><table tabindex="0"><thead><tr><th>문서</th><th>보강한 판단 근거</th></tr></thead><tbody><tr><td>Kafka Incident Monitoring</td><td>장애를 로그 검색이 아니라 고객사·도메인·배포·설정 변경 기준으로 분류한 이유</td></tr><tr><td>DUCOS</td><td>tenant override와 runtime refresh가 운영 위험이 되는 지점</td></tr><tr><td>OpenResty L7</td><td>범용 gateway가 아니라 조직 정책 경계가 필요한 이유</td></tr><tr><td>CALS</td><td>근태 데이터가 최신 상태가 아니라 사건 원장으로 남아야 하는 이유</td></tr><tr><td>PlanVM / DBHub</td><td>변경 가능한 업무 정책과 운영 DB 접근을 통제 가능한 실행 행위로 바꾼 기준</td></tr><tr><td>Agent</td><td>자연어 이해와 업무 실행을 분리하고 fallback chain을 제한한 이유</td></tr><tr><td>Messaging / WebRTC</td><td>session, sequence, media path, reconnect를 운영 책임으로 다룬 기준</td></tr><tr><td>Tax / Task / Deployment</td><td>계산 trace, task state, bundle version, rollback을 검증 가능한 기록으로 남긴 이유</td></tr></tbody></table><p>따라서 이 포트폴리오는 기술 스택 목록이 아니라, 운영 중인 시스템을 안전하게 변경하기 위해 어떤 제약을 받아들였는지 설명하는 문서 묶음이다.</p><h2 id="한눈에-보는-주제" tabindex="-1">한눈에 보는 주제 <a class="header-anchor" href="#한눈에-보는-주제" aria-label="Permalink to &quot;한눈에 보는 주제&quot;">​</a></h2><table tabindex="0"><thead><tr><th>영역</th><th>문서</th><th>핵심 주제</th></tr></thead><tbody><tr><td>운영 실행</td><td>PlanVM, Task Manager</td><td>정책 실행, scheduler, audit, rollback</td></tr><tr><td>데이터 접근</td><td>DBHub</td><td>운영 DB 접근 통제, masking, 승인, trace</td></tr><tr><td>장애 대응</td><td>Kafka Monitoring</td><td>장애 이벤트, 원인 후보, 해결 힌트, 운영 지식화</td></tr><tr><td>트래픽 제어</td><td>OpenResty L7, Zero Downtime Deployment</td><td>routing, canary, blue-green, 배포 전환</td></tr><tr><td>실시간 통신</td><td>Messaging System, WebRTC, LiveKit and Janus</td><td>gateway, broker, session, media path, tail latency</td></tr><tr><td>분산 설정</td><td>Cloud Config and Discovery</td><td>tenant, stage, override, runtime refresh</td></tr><tr><td>업무 원장</td><td>CALS, Year-end Tax Calculator</td><td>SOT, 정합성, 계산 trace, 설명 가능성</td></tr><tr><td>Agent</td><td>AI Agent</td><td>자연어 이해, 통제 실행, 도메인 catalog, 용어사전</td></tr></tbody></table>',17)])])}const g=a(o,[["render",i]]);export{f as __pageData,g as default};
